- Correlation via function call name

### Cursor/Other Formats
- Various structures, need to detect and handle

### OpenCode Format
- Special handling already exists (is_opencode flag)

## Algorithm Design

```rust
/// Message classification for grouping
#[derive(Debug, Clone, Copy, PartialEq)]
enum MessageClassification {
    UserContent,        // User message with actual text
    AssistantContent,   // Assistant with text (may also have tools)
    AssistantToolOnly,  // Assistant with only tool calls, no text
    ToolResult,         // Response to a tool call
    System,             // System message
    Empty,              // No content, skip
}

/// Groups flat messages into MessageGroups with tool correlation.
/// 
/// # Algorithm
/// 1. Classify each message
/// 2. User/Assistant content messages start new groups
/// 3. Tool-only messages attach to current assistant group
/// 4. Tool results correlate by ID to matching tool call
/// 5. System messages standalone
/// 6. Track timestamps for group range
///
/// # Logging
/// - INFO: Group formation summary
/// - DEBUG: Each message classification
/// - TRACE: Correlation matching details
pub fn group_messages_for_export(
    messages: Vec<Message>,
    agent_format: AgentFormat,
) -> Vec<MessageGroup> {
    info!(message_count = messages.len(), "Starting message grouping");
    let mut groups = Vec::new();
    let mut current_group: Option<MessageGroup> = None;

    for (idx, msg) in messages.iter().enumerate() {
        let classification = classify_message(msg, agent_format);
        debug!(idx, ?classification, role = %msg.role, "Classified message");

        match classification {
            MessageClassification::UserContent => {
                flush_group(&mut groups, &mut current_group);
                current_group = Some(MessageGroup::new(msg.clone(), MessageGroupType::User));
            }
            MessageClassification::AssistantContent => {
                flush_group(&mut groups, &mut current_group);
                let mut group = MessageGroup::new(msg.clone(), MessageGroupType::Assistant);
                // If assistant has embedded tool calls, add them
                if let Some(tc) = &msg.tool_call {
                    group.add_tool_call(tc.clone(), extract_correlation_id(msg));
                }
                current_group = Some(group);
            }
            MessageClassification::AssistantToolOnly => {
                // Attach to current group or create tool-only group
                if let Some(ref mut g) = current_group {
                    if let Some(tc) = &msg.tool_call {
                        g.add_tool_call(tc.clone(), extract_correlation_id(msg));
                    }
                } else {
                    current_group = Some(MessageGroup::new(msg.clone(), MessageGroupType::ToolOnly));
                }
            }
            MessageClassification::ToolResult => {
                if let Some(ref mut g) = current_group {
                    let result = ToolResult::from_message(msg);
                    g.add_tool_result(result);
                } else {
                    debug!(idx, "Orphan tool result, skipping");
                }
            }
            MessageClassification::System => {
                flush_group(&mut groups, &mut current_group);
                groups.push(MessageGroup::new(msg.clone(), MessageGroupType::System));
            }
            MessageClassification::Empty => {
                trace!(idx, "Skipping empty message");
            }
        }
    }

    flush_group(&mut groups, &mut current_group);
    info!(group_count = groups.len(), "Message grouping complete");
    groups
}
```

